INSERT INTO tasks VALUES('7279c571-4196-469e-b7c5-cd87b9e91c65',-1003725299009,2061134525,'text','тест','ARCHIVED',replace('Тестовая проверка работоспособности системы выполнена.  \nТекущий контур: Telegram -> telegram_daemon.py -> core.db -> task_worker.py -> core/ai_router.py -> OpenRouter -> Telegram.  \nВсе ключевые процессы (memory_api_server.py, telegram_daemon.py, task_worker.py) активны.  \nЛоги доступны для анализа.  \nСистема готова к выполнению задач.','\n',char(10)),NULL,2810,'2026-04-11T16:07:08.351131+00:00','2026-04-11T16:07:15.524749+00:00');
