INSERT INTO tasks VALUES('7019de9d-bc67-4d65-9edc-75d3d1b0f64c',-1003725299009,8393501592,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_2896.ogg','ARCHIVED','Цена бетона М300 в Москве была взята из открытых источников и может варьироваться в зависимости от поставщика. Уточняйте у конкретных компаний.',NULL,2896,'2026-04-11T22:33:20.469391+00:00','2026-04-11T22:33:25.672214+00:00');
