INSERT INTO tasks VALUES('d17318b9-7160-4ffe-ab3b-baa5c75cc3e3',-1003725299009,8393501592,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_2904.ogg','ARCHIVED','Если речь идёт о Санкт-Петербурге, система продолжит обрабатывать текстовые запросы в рамках текущего MVP-ядра. Контекст памяти будет использоваться для краткосрочного хранения данных, связанных с чатом. Ответы будут формироваться через OpenRouter с учётом русской системной инструкции. Если запрос касается конкретной информации о городе, система попытается дать ответ на основе доступных данных или контекста.',NULL,2904,'2026-04-11T22:47:02.772747+00:00','2026-04-11T22:47:10.966928+00:00');
