INSERT INTO tasks VALUES('a7d57f69-dda4-4c80-baac-123f1401649a',-1003725299009,2061134525,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_2937.ogg','ARCHIVED',replace('1. Telegram бот (@ai_orkestra_all_bot) принимает сообщения через aiogram.  \n2. Задачи пишутся в core.db (таблица tasks).  \n3. Воркер (task_worker.py) обрабатывает задачи по очереди.  \n1. AI роутер (ai_router.py) делает запросы к OpenRouter.  \n2. Память хранится в memory.db через memory_api_server.py.  \n3. Работает в режиме MVP (только текстовые сообщения).','\n',char(10)),NULL,2937,'2026-04-11T23:10:48.939549+00:00','2026-04-11T23:14:01.031038+00:00');
INSERT INTO tasks VALUES('5e459c61-4779-4cfb-a2cb-dcd4f47cd738',-1003725299009,2061134525,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_2941.ogg','ARCHIVED',replace('Сейчас система не отображает текст голосовых сообщений, так как контур распознавания речи ещё не подключен. Для отображения текста голосовых сообщений нужно добавить функционал преобразования голоса в текст (например, через Speech-to-Text API) и модифицировать `ai_router.py` для обработки таких сообщений. \n\nПока можно дублировать голосовые сообщения текстом вручную или добавить заглушку с уведомлением о получении голосового сообщения и предложением продублировать его текстом. \n\nЕсли нужно срочное решение, можно временно модифицировать `telegram_daemon.py` для принудительного отклонения голосовых сообщений с просьбой отправить текст.','\n',char(10)),NULL,2941,'2026-04-11T23:14:18.945518+00:00','2026-04-11T23:14:25.362910+00:00');
