INSERT INTO tasks VALUES('74d48f4c-f90c-4d2c-8d98-4c4ace17b594',-1003725299009,2061134525,'text','Да','DONE',replace('Не нашёл конкретного запроса. Укажите, что именно нужно проверить или получить. Например:  \n\n- **Статус процессов** (telegram_daemon.py, task_worker.py, memory_api_server.py)  \n- **Логи** (уточните модуль и количество строк)  \n- **Данные из memory.db/core.db** (укажите chat_id или таблицу)  \n- **Ошибки** (опишите симптомы)  \n\nПримеры:  \n*«Покажи последние 5 строк из logs/task_worker.log»*  \n*«Есть ли задачи в core.db с state=''NEW''?»*  \n\nЖду уточнений.','\n',char(10)),NULL,3287,'2026-04-12T12:18:23.156798+00:00','2026-04-12T12:18:31.311890+00:00');
INSERT INTO tasks VALUES('6bb390a8-3775-4f6e-8b3a-fc926882ec19',-1003725299009,2061134525,'text','А с чего ты взял что задача завершена и почему ты вообще сделал такие вы','DONE',replace('Ваш запрос звучит как вопрос о логике завершения задач в системе. Давайте разберёмся:\n\n1. **Задача завершается в `task_worker.py`** после выполнения следующих шагов:\n   - Выбирается задача с состоянием `state=''NEW''`.\n   - Состояние задачи меняется на `state=''IN_PROGRESS''`.\n   - Вызывается функция `process_ai_task`, которая отправляет запрос в OpenRouter через `ai_router.py`.\n   - Если ответ от OpenRouter получен, он отправляется в Telegram через `reply_sender.py`.\n   - После успешной отправки ответа состояние задачи обновляется на `state=''COMPLETED''` (или другое финальное состояние, если указано в логике).\n   - Если ответ пустой или произошла ошибка, задача переходит в состояние `state=''ERROR''` с соответствующим сообщением об ошибке.\n\n2. **Почему задача считается завершённой?**\n   - Задача завершается, когда она прошла все этапы обработки: от получения входных данных до отправки ответа в Telegram. Это фиксируется изменением состояния задачи в базе данных `core.db`.\n\n3. **Почему сделаны такие выводы?**\n   - Логика завершения задач основана на принципе конечного автомата (state machine), где каждая задача проходит через определённые состояния (`NEW` → `IN_PROGRESS` → `COMPLETED`/`ERROR`). Это стандартный подход для обработки задач в асинхронных системах.\n\nЕсли у вас есть конкретные вопросы или проблемы с завершением задач, уточните, например:\n- Какая задача не завершается?\n- Есть ли ошибки в логах `task_worker.log`?\n- Нужно ли проверить состояние конкретной задачи в `core.db`?','\n',char(10)),NULL,3290,'2026-04-12T12:21:04.474339+00:00','2026-04-12T12:21:36.270911+00:00');
