INSERT INTO tasks VALUES('a997dbf9-d383-4625-9094-cc15f95a62c3',-1003725299009,2061134525,'text','Да','DONE',replace('Не нашёл конкретного запроса. Уточните, что именно нужно проверить или получить. Например:  \n\n- **Статус процессов** (telegram_daemon.py, task_worker.py, memory_api_server.py)  \n- **Логи** (уточните модуль и количество строк)  \n- **Данные из memory.db/core.db** (укажите chat_id или таблицу)  \n- **Ошибки** (опишите симптомы)  \n\nПримеры:  \n*«Покажи последние 5 строк из logs/task_worker.log»*  \n*«Есть ли ошибки в memory_api.log?»*  \n*«Выведи последние задачи из core.db»*','\n',char(10)),NULL,3366,'2026-04-12T16:10:25.074320+00:00','2026-04-12T16:10:36.951796+00:00');
INSERT INTO tasks VALUES('b26bc9a7-9afe-44d0-bba7-878a4374260e',-1003725299009,2061134525,'text','{“chat_id”:“UNKNOWN”,“exported_at”:“2026-04-12T18:15:00Z”,“source_platform”:“ChatGPT”,“source_model”:“UNKNOWN”,“system”:“AREAL-NEVA CORE ORCHESTRA; server-first; Telegram interface; OpenRouter LLM; SQLite memory; file memory ingest and dump layer; eZone-compatible memory export workflow”,“architecture”:“Telegram -> /root/.areal-neva-core/telegram_daemon.py -> eZone auto-ingest to /root/.areal-neva-core/data/memory_files or ordinary task insert into /root/.areal-neva-core/data/core.db -> /root/.areal-neva-core/task_worker.py -> /root/.areal-neva-core/core/ai_router.py -> OpenRouter API -> memory write/read via /root/.areal-neva-core/memory_api_server.py and /root/.areal-neva-core/data/memory.db -> Telegram reply”,“pipeline”:“For ordinary tasks: message intake -> create_task in core.db with state NEW -> task_worker picks task -> ai_router processes -> OpenRouter call or fallback -> result persisted -> reply flow. For eZone memory ingest: Telegram text or file with valid normalized JSON containing at least one of system, architecture, pipeline, memory -> direct save into CHATS raw.json and timeline.jsonl, GLOBAL timeline.jsonl, SYSTEM .jsonl -> immediate short acknowledgment -> no create_task, no worker, no confirmation. For memory dump: text trigger reads only file memory from GLOBAL, CHATS, SYSTEM and returns text dump”,“memory”:“Two layers exist. Working SQLite memory: /root/.areal-neva-core/data/memory.db with table memory(id, chat_id, key, value, timestamp), written through POST /memory and read through GET /memory, with sqlite fallback in ai_router. File memory: /root/.areal-neva-core/data/memory_files with GLOBAL, CHATS, SYSTEM, ERRORS. eZone ingest writes append-only timeline.jsonl files and SYSTEM/.jsonl, with CHATS/<chat_id>/raw.json as the only overwrite exception. Dump reads only file memory, not memory.db”,“integrations”:“Telegram via aiogram polling, OpenRouter via HTTPS POST to https://openrouter.ai/api/v1/chat/completions, memory API via Flask on 127.0.0.1:8091, STT via whisper-large-v3-turbo with Groq environment observed in logs, Google Drive not implemented in the confirmed working state”,“files”:[”/root/.areal-neva-core/telegram_daemon.py”,”/root/.areal-neva-core/task_worker.py”,”/root/.areal-neva-core/core/ai_router.py”,”/root/.areal-neva-core/memory_api_server.py”,”/root/.areal-neva-core/data/core.db”,”/root/.areal-neva-core/data/memory.db”,”/root/.areal-neva-core/data/memory_files/GLOBAL/timeline.jsonl”,”/root/.areal-neva-core/data/memory_files/CHATS/<chat_id>/raw.json”,”/root/.areal-neva-core/data/memory_files/CHATS/<chat_id>/timeline.jsonl”,”/root/.areal-neva-core/data/memory_files/SYSTEM/system.jsonl”,”/root/.areal-neva-core/data/memory_files/SYSTEM/architecture.jsonl”,”/root/.areal-neva-core/data/memory_files/SYSTEM/pipeline.jsonl”,”/root/.areal-neva-core/data/memory_files/SYSTEM/memory.jsonl”,”/root/.areal-neva-core/data/memory_files/ERRORS/errors.log”,”/root/.areal-neva-core/logs/telegram_daemon.log”,”/root/.areal-neva-core/logs/task_worker.log”,”/root/.areal-neva-core/logs/memory_api.log”,”/root/.areal-neva-core/runtime/voice_queue”],“services”:[“telegram_daemon.py”,“task_worker.py”,“memory_api_server.py”],“env”:[“OPENROUTER_API_KEY”,“OPENROUTER_MODEL”,“TELEGRAM_BOT_TOKEN”,“MEMORY_API_TOKEN”,“ORCHESTRA_SNAPSHOT_CHAT_ID”],“db”:“core.db contains tasks(id, chat_id, user_id, input_type, raw_input, state, result, error_message, reply_to_message_id, created_at, updated_at). memory.db contains memory(id, chat_id, key, value, timestamp) with index on chat_id. Confirmed task states seen in chat and logs include NEW, IN_PROGRESS, AWAITING_CONFIRMATION, DONE, FAILED, ARCHIVED”,“logic”:“Ordinary text and voice go through create_task and worker lifecycle. Voice messages are downloaded to runtime/voice_queue and transcribed before further processing. ai_router reads file memory in ordered context, reads DB memory, may call web search, and has LLM fallback to file-memory search.','ARCHIVED',replace('Понял задачу так: {“chat_id”:“UNKNOWN”,“exported_at”:“2026-04-12T18:15:00Z”,“source_platform”:“ChatGPT”,“source_model”:“UNKNOWN”,“system”:“AREAL-NEVA CORE ORCHESTRA; server-first; Telegram interface; OpenRouter LLM; SQLite memory; file memory ingest and dump layer; eZone-compatible memory export workflow”,“architectu\n\nПодтверди или уточни','\n',char(10)),NULL,3369,'2026-04-12T16:10:58.761999+00:00','2026-04-12T16:11:00.459399+00:00');
INSERT INTO tasks VALUES('53570fdb-ebb8-4962-8e07-137fafb8b150',-1003725299009,2061134525,'text','eZone memory ingest must bypass create_task, bypass worker, bypass confirmation, save directly to file memory, and reply immediately with a short acknowledgment. Dump triggers are text commands only and must bypass worker and confirmation”,“decisions”:“File memory is the canonical exportable orchestra memory. SQLite memory remains working internal memory. SYSTEM must be stored only as append-only jsonl files. eZone ingest must support both text and file inputs. Only the paths GLOBAL, CHATS, SYSTEM are used for orchestra memory dump. The old stack tg_agent, storage_layer, orchestra.db was removed from the confirmed core baseline. OpenRouter is the single LLM in the confirmed baseline. The prompt template for universal chat memory export must use only ASCII double quotes and strictly valid JSON”,“solutions”:“Implemented or confirmed in chat: eZone direct ingest concept, append-only file memory structure, SYSTEM jsonl storage, dump triggers for file memory, ai_router file-memory context reading, ai_router fallback to file-memory search, JSON input normalization for typographic quotes, single-handler approach for telegram_daemon to enforce branch order, dump formatting with GLOBAL, CHAT, SYSTEM sections, restart protocol with log output after fixes”,“code”:“Critical logic includes normalized JSON parsing before eZone detection; eZone detection by presence of at least one of system, architecture, pipeline, memory; direct save into CHATS/<chat_id>/raw.json plus append to CHATS/<chat_id>/timeline.jsonl and GLOBAL/timeline.jsonl plus append to SYSTEM/.jsonl; ordinary tasks inserted into core.db as NEW; ai_router reads SYSTEM, GLOBAL, current CHAT, related CHATS, DB memory, and web data in ordered context; ai_router OpenRouter response extracted from choices[0].message.content; dump command reads only file memory and outputs sections in text form”,“errors”:[“Typographic quotes in exported JSON -> JSON parsing failed and eZone ingest was not triggered”,“eZone message entered create_task and worker -> handler order or detection logic in telegram_daemon.py needed tightening”,“SYSTEM data written as .json with overwrite -> moved to append-only SYSTEM/.jsonl”,“SYSTEM context lost in ai_router -> add explicit section headers and sorted reading order”,“Dump and related context order unstable -> apply sorted iteration and fixed section formatting”,“task_worker archived tasks with already has result -> ordinary task reply lifecycle remained broken”,“Voice tasks transcribed successfully but then hit ARCHIVE stuck path -> worker/reply path still broken”,“Using multiple F.text handlers with incorrect stop propagation assumption -> replaced with single ordered universal handler concept”,“Valid JSON without eZone keys treated as error and replied NЕТ -> changed to ordinary task path”,“Universal export prompt contained smart quotes -> replaced with ASCII double quotes only”],“state”:“Confirmed working now: telegram_daemon and task_worker processes start, memory file dump mechanism produced output, eZone ingest path concept works enough to produce a file-memory dump after normalization fix, ai_router file-memory context and fallback logic were patched conceptually and code versions were iterated. Confirmed still broken: ordinary worker reply lifecycle with ARCHIVE stuck behavior, voice and some text tasks entering confirmation or archive paths instead of completing cleanly, and overall worker/reply stability”,“limits”:“No confirmed Google Drive integration in the validated working state. No confirmed file pipeline beyond orchestra file memory. No confirmed OCR, document_engine, estimate_engine, or DWG pipeline in the validated working state. Universal export quality still depends on external model compliance. Worker and reply path remain unstable for ordinary tasks. The exact chat identifier for this conversation is unknown”,“pending”:“Fix task_worker ordinary lifecycle and reply path, especially ARCHIVE stuck behavior. Stabilize reply sender for Telegram replies. Finalize eZone file and text auto-ingest behavior against real logs only.','ARCHIVED',replace('Понял задачу так: eZone memory ingest must bypass create_task, bypass worker, bypass confirmation, save directly to file memory, and reply immediately with a short acknowledgment. Dump triggers are text commands only and must bypass worker and confirmation”,“decisions”:“File memory is the canonical exportable orchest\n\nПодтверди или уточни','\n',char(10)),NULL,3370,'2026-04-12T16:10:58.807753+00:00','2026-04-12T16:11:01.770756+00:00');
