INSERT INTO tasks VALUES('7ba0d533-2655-435b-b2c8-8e9650e67b48',-1003725299009,543179966,'text','Да уточняю как твои дела что ты все от отваливается ся на хуй тут мудаки эти заебали меня уже тебя чинить','DONE',replace('Текущее состояние системы:  \n- Ядро работает (Telegram → OpenRouter → Telegram)  \n- Память доступна через memory_api_server.py  \n- Обработка текста активна, голосовые сообщения не поддерживаются  \n\nОшибки в логах:  \n- Ранее были проблемы с переходами состояний задач (NEW → IN_PROGRESS)  \n- Фиксы уже внедрены (кавычки в SQL, очистка кеша)  \n\nЧто можно сделать:  \n1. Проверить логи (`/root/.areal-neva-core/logs/task_worker.log`)  \n2. Уточнить конкретную проблему (падения, ошибки API и т.д.)  \n3. Добавить данные в память, указав chat_id, ключ и значение  \n\nСистема готова к работе. Уточните детали проблемы для точного решения.','\n',char(10)),NULL,3483,'2026-04-12T22:14:13.553791+00:00','2026-04-12T22:14:22.062378+00:00');
