INSERT INTO tasks VALUES('c9b8009c-63d8-46e2-8bd6-00e29b514585',-1003725299009,543179966,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_3499.ogg','DONE',replace('Понял задачу так: Дружище Варик, ты у меня здесь? Нет? Как у тебя память-то появилась, не появилась?\n\nПодтверди или уточни','\n',char(10)),NULL,3499,'2026-04-12T23:40:22.740173+00:00','2026-04-12T23:40:23.902654+00:00');
