INSERT INTO tasks VALUES('e1ba7f0c-f2cc-4612-bd05-e02d700a30d0',-1003725299009,543179966,'text','Отбой задач','DONE',replace('Отбой задач в системе AREAL-NEVA CORE выполняется через очистку таблицы tasks в core.db. Для этого:\n\n1. Остановите task_worker.py и telegram_daemon.py\n2. Выполните SQL-запрос:\n```sql\nDELETE FROM tasks WHERE state IN (''NEW'', ''IN_PROGRESS'');\n```\n3. Перезапустите процессы\n\nДля отбоя только конкретных типов задач добавьте условие WHERE по полям input_type или chat_id.','\n',char(10)),NULL,3503,'2026-04-12T23:40:48.814881+00:00','2026-04-12T23:40:56.505377+00:00');
