INSERT INTO tasks VALUES('4f043928-4bba-42d6-b473-1ecbbce83a17',-1003725299009,2061134525,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_3597.ogg','FAILED','Похоже, вы указали путь к голосовому файлу в системе. Однако, в текущей реализации системы AREAL-NEVA CORE, голосовые сообщения не поддерживаются. Если вам нужно обрабатывать или управлять этим файлом, пожалуйста, уточните, что именно вы хотите сделать с ним. Возможно, вам потребуется конвертировать его в текстовый формат или выполнить другую задачу.','timeout',3597,'2026-04-13T09:53:26.297219+00:00','2026-04-13T09:53:28.245184+00:00');
