INSERT INTO tasks VALUES('40b861e9-b89a-4263-b66f-dc6d824a9772',-1003725299009,2061134525,'text','Я тебе написал что я от тебя хочу','FAILED',replace('Понял, вы хотите отобрать задачи в системе AREAL-NEVA CORE. Давайте уточним, какие задачи вы хотите отменить:\n\n1. Вы хотите отменить все новые и текущие задачи?\n2. Или вас интересует отбой конкретных задач по определенному параметру (например, по chat_id или input_type)?\n\nПожалуйста, уточните, чтобы я мог предоставить вам точную инструкцию.','\n',char(10)),'timeout',3603,'2026-04-13T10:05:58.961517+00:00','2026-04-13T10:06:34.224181+00:00');
INSERT INTO tasks VALUES('f5052fd5-c4d2-4ee0-aacc-4ecea3920d26',-1003725299009,2061134525,'text','Я тебе уже все написал выше перечитай пожалуйста','DONE',replace('Извините за недоразумение. Давайте я резюмирую информацию по текущему состоянию системы и вашим запросам, чтобы уточнить, что именно вам нужно:\n\n1. **Текущее состояние системы**:  \n   - Ядро работает (Telegram → OpenRouter → Telegram).\n   - Память доступна через memory_api_server.py.\n   - Обработка текста активна, голосовые сообщения не поддерживаются.\n\n2. **Ошибки в логах**:  \n   - Ранее были проблемы с переходами состояний задач (NEW → IN_PROGRESS).\n   - Фиксы уже внедрены.\n\n3. **Ваш запрос по отбытию задач**:  \n   - Вы хотите отменить задачи в системе AREAL-NEVA CORE и уточняете, как это сделать.\n\nПожалуйста, уточните, что именно еще вы хотели бы обсудить или изменить.','\n',char(10)),NULL,3607,'2026-04-13T10:06:42.145046+00:00','2026-04-13T10:07:14.745333+00:00');
INSERT INTO tasks VALUES('9126b7a6-1e8c-4a0b-9544-f16a7bd49001',-1003725299009,2061134525,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_3611.ogg','FAILED',replace('Похоже, вы указали путь к файлу голосового сообщения в очереди. Однако, как упоминалось ранее, система в текущий момент не поддерживает обработку голосовых сообщений.\n\nЕсли вам нужно обработать это голосовое сообщение или выполнить какие-либо действия с ним, пожалуйста, уточните, что именно вы хотели бы сделать. Например:\n1. Загружать аудиофайл для преобразования в текст?\n2. Отменить задачу, связанную с этим сообщением?\n3. Или что-то иное?\n\nСообщите, пожалуйста, детали, чтобы я мог вам помочь!','\n',char(10)),'timeout',3611,'2026-04-13T10:16:45.410067+00:00','2026-04-13T10:16:49.740324+00:00');
INSERT INTO tasks VALUES('3bedbaf6-83b4-4f32-a56b-bcf1143e8a80',-1003725299009,2061134525,'voice','/root/.areal-neva-core/runtime/voice_queue/voice_1003725299009_3613.ogg','FAILED',replace('Похоже, вы указали путь к файлу голосового сообщения в очереди. Однако система в текущий момент не поддерживает обработку голосовых сообщений.\n\nЕсли вам нужно выполнить какие-либо действия с этим сообщением, пожалуйста, уточните, что именно вы хотите сделать. Например:\n1. Загружать аудиофайл для преобразования в текст?\n2. Отменить задачу, связанную с этим сообщением?\n3. Или что-то иное?\n\nСообщите, пожалуйста, детали, чтобы я мог вам помочь!','\n',char(10)),'timeout',3613,'2026-04-13T10:17:03.045222+00:00','2026-04-13T10:17:50.397416+00:00');
