INSERT INTO tasks VALUES('71279879-5a03-42b3-bf51-edfe013fb717',-1003725299009,2061134525,'text','Я хочу чтобы ты запомнил то что я тебе сказал и напиши кто сейчас общается со мной ты представитель оркестра от чего имени ты ведёшь сейчас диалог','FAILED','Я представитель оркестра AREAL-NEVA CORE и веду диалог от имени системы. В данный момент с вами общается Илья, и я здесь, чтобы помочь вам с вашими вопросами и задачами. Ваши слова запомнены. Чем могу помочь?','timeout',3786,'2026-04-13T14:20:30.330095+00:00','2026-04-13T14:20:33.387207+00:00');
INSERT INTO tasks VALUES('95a43d02-e78a-46a5-ad95-6e6a7c3e88cc',-1003725299009,2061134525,'text','Скажи какие нейронные сети сейчас в составе оркестра Ареал Нева Core','FAILED',replace('В составе оркестра AREAL-NEVA CORE в данный момент используются следующие нейронные сети:\n\n1. **OpenRouter LLM** - это основная языковая модель, которая обрабатывает текстовые запросы и генерирует ответы.\n2. **Модель для распознавания речи (STT)** - отвечает за преобразование голосовых сообщений в текст. Однако стоит отметить, что в текущей конфигурации акцент сделан на текстовой обработке, и голосовые сообщения не поддерживаются.\n\nЕсли у вас есть дополнительные вопросы или требуется информация по конкретной модели, дайте знать!','\n',char(10)),'timeout',3788,'2026-04-13T14:20:50.843921+00:00','2026-04-13T14:20:55.085871+00:00');
INSERT INTO tasks VALUES('c7db1c8e-5bae-4410-9891-a75f8993c791',-1003725299009,2061134525,'text','И все что ли ты уверен в этом точно?','FAILED',replace('Да, я могу подтвердить информацию о нейронных сетях в составе оркестра Ареал Нева Core. В данный момент используются:\n\n1. **OpenRouter LLM** - основная языковая модель для обработки текстовых запросов и генерации ответов.\n2. **Модель для распознавания речи (STT)** - для преобразования голосовых сообщений в текст, хотя основное внимание уделяется текстовой обработке.\n\nЕсли у вас возникли дополнительные вопросы или вам нужна уточняющая информация, дайте знать!','\n',char(10)),'timeout',3790,'2026-04-13T14:21:14.554129+00:00','2026-04-13T14:21:30.351532+00:00');
INSERT INTO tasks VALUES('52b3d780-2057-4abe-8b9a-94571e0c6af7',-1003725299009,2061134525,'text','Ничего блядь я же сказал','FAILED','Извините, если я не так понял ваш запрос. Могу ли я чем-то помочь или уточнить информацию?','timeout',3794,'2026-04-13T14:21:36.645287+00:00','2026-04-13T14:21:39.125716+00:00');
