INSERT INTO tasks VALUES('4c9c7b33-2482-4997-8b2c-8c004e6ce456',-1003725299009,2061134525,'text','орик','FAILED','Орик — это персонаж из серии игр "Warcraft" и "World of Warcraft", созданный Blizzard Entertainment. Он является принцем народа дракари, древней расы, которая стала основой для орков в современном мире Азерота. Орик известен своей мудростью, силой и ролью в истории орков. Если у вас есть конкретные вопросы о нем, уточните!','timeout',3934,'2026-04-13T23:34:45.603669+00:00','2026-04-14T00:16:08.741122+00:00');
