INSERT INTO tasks VALUES('c6888c2d-a6b2-4959-9d0a-74cebc6ece86',-1003725299009,2061134525,'voice','проверка голоса как работает голос ответь мне пожалуйста','FAILED',replace('**Как работает проверка голоса:**  \n\n1. **Запись голоса** – система записывает ваш голос через микрофон.  \n2. **Анализ параметров** – сравнивает уникальные характеристики (тональность, тембр, ритм) с эталоном.  \n3. **Принятие решения** – подтверждает или отклоняет личность на основе совпадений.  \n\n**Примеры использования:**  \n- Разблокировка устройств (например, голосовой пароль).  \n- Идентификация в банковских сервисах.  \n- Доступ к защищённым системам.  \n\nНужны уточнения? Готов помочь! 🎤','\n',char(10)),'timeout',3948,'2026-04-14T11:35:46.499915+00:00','2026-04-14T11:35:53.758228+00:00');
