PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE tasks (id TEXT PRIMARY KEY, chat_id INTEGER, user_id INTEGER, input_type TEXT, raw_input TEXT, state TEXT DEFAULT "NEW", result TEXT, error_message TEXT, reply_to_message_id INTEGER, created_at TEXT, updated_at TEXT);
CREATE TABLE processed_updates (update_id INTEGER PRIMARY KEY, created_at TEXT);
CREATE TABLE task_history (id INTEGER PRIMARY KEY AUTOINCREMENT, task_id TEXT, action TEXT, created_at TEXT);
CREATE TABLE pin (id INTEGER PRIMARY KEY AUTOINCREMENT, chat_id TEXT, task_id TEXT, state TEXT, created_at TEXT, updated_at TEXT);
CREATE TABLE drive_files (id INTEGER PRIMARY KEY AUTOINCREMENT, task_id TEXT, drive_file_id TEXT, file_name TEXT, mime_type TEXT, stage TEXT, created_at TEXT);
DELETE FROM sqlite_sequence;
COMMIT;
